import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge cases — simplest first
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // Base premiums for single items (with fee, no other modifiers, year=0 first-quote)
  it.todo("single sword (steel, ench 3, not cursed), 0 years, first quote → 100 base + 10 first-insurance + 5 fee = 115 G");
  it.todo("single amulet (silver, ench 2, not cursed), 0 years, first quote → 60 base + 6 first-insurance + 5 fee = 71 G");
  it.todo("single staff (wood, ench 2, not cursed), 0 years, first quote → 80 base + 8 first-insurance + 5 fee = 93 G");
  it.todo("single potion (glass, ench 2, not cursed), 0 years, first quote → 40 base + 4 first-insurance + 5 fee = 49 G");

  // Components — building block of 3 alike
  it.todo("2 runes → base premium 50 G (no block)");
  it.todo("3 runes → base premium 60 G (block applies)");
  it.todo("4 runes → base premium 100 G (no block; block requires exactly 3)");
  it.todo("7 runes → base premium 175 G (no block applies — 7 runes is 7 × 25)");

  // "Alike" components — same type required
  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet → policy base 160 G + 50 G (50% of cursed item base only) = 210 G before further modifiers");

  // Modifier thresholds — premium
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // Rounding — premium rounded up (MHPCO's favor)
  it.todo("premium that yields 197.5 G → final premium 198 G (rounded up)");

  // Integration examples from spec
  it.todo("Newcomer with cursed sword (steel, ench 3), 0 years → 165 G");
  it.todo("Long-standing customer's second contract: 3 years, cursed sword ench 7, 2nd quote → 160 G");

  // Errors on quote
  it.todo("quote includes item with unknown type → non-zero exit, no results written");

  // ===== CLAIMS =====

  // Standard reimbursement (no special clauses)
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to rune (insurance value 250 G), damage 200 G → payout 100 G");

  // Enchantment threshold for claims
  it.todo("dragon-material sword with exactly ench 8, damage 1000 G → payout 400 G (50% rule, then deductible)");
  it.todo("dragon-material sword ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword ench 5, damage 800 G → payout 700 G (only dragon clause; full minus deductible)");
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (only high-enchantment clause)");

  // Deductible per damage event
  it.todo("dragon attack on sword (500 G) and amulet (300 G) → payout 600 G (deductible applies once per damaged item)");

  // Multiple items of the same type
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; two sword damages → each gets its own deductible");
  it.todo("damages contains more entries of a type than insured → claim rejected, non-zero exit");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword cap 2000 G; first claim 1500 G → payout 1400 G, remainingCap 600 G");
  it.todo("sword cap 2000 G; second claim 1500 G after first 1500 G claim → payout 600 G, remainingCap 0 G");

  // Rounding for payouts — rounded down (MHPCO's favor)
  it.todo("payout that yields 350.5 G → final payout 350 G (rounded down)");

  // Claim errors
  it.todo("claim references damage for item not in policy → non-zero exit, stderr error");
  it.todo("claim contains damage with amount: -200 → non-zero exit, stderr error");
});

