interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}
interface QuoteStep {
  op: "quote";
  items: Item[];
}
interface Item {
  type: string;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

function computeQuote(step: QuoteStep): { premium: number } {
  const itemBaseSum = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const premium = itemBaseSum + itemBaseSum * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
}

export function runScenario(input: Scenario): unknown {
  return { results: input.steps.map(computeQuote) };
}

