interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}
interface QuoteStep {
  op: "quote";
  items: Item[];
}
interface Item {
  type: string;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const MAIN_ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
const COMPONENT_BASE_PER_UNIT = 25;
const COMPONENT_BLOCK_BASE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function componentBaseForCount(count: number): number {
  if (count === 3) return COMPONENT_BLOCK_BASE;
  return count * COMPONENT_BASE_PER_UNIT;
}

function itemsBaseSum(items: Item[]): number {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += MAIN_ITEM_BASE[item.type];
    }
  }
  for (const count of Object.values(componentCounts)) {
    total += componentBaseForCount(count);
  }
  return total;
}

function computeQuote(step: QuoteStep): { premium: number } {
  const base = itemsBaseSum(step.items);
  const premium = base + base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
}

export function runScenario(input: Scenario): unknown {
  return { results: input.steps.map(computeQuote) };
}

